// First screen
Future<void> _navigateAndGetSelection() async {
  final result = await Navigator.push(
    context,
    MaterialPageRoute(builder: (context) => SelectionScreen()),
  );
  // result is whatever was passed to pop()
  print('Selected: $result');
}

// Selection screen
ElevatedButton(
  onPressed: () {
    Navigator.pop(context, 'Option 1');
  },
  child: Text('Option 1'),
);
